import asyncio
import uuid
from dataclasses import dataclass, field

@dataclass
class PendingQuestion:
    id: str = field(default_factory=lambda: str(uuid.uuid4()))
    question: str = ""
    options: list[str] | None = None   # None = free-form; list = forced-choice
    default: str | None = None
    answer_event: asyncio.Event = field(default_factory=asyncio.Event)
    answer: str | None = None

_questions: dict[str, PendingQuestion] = {}

ASK_HUMAN_TOOL = {
    "name": "ask_human",
    "description": (
        "Ask the human operator a single clarifying question when you cannot proceed "
        "without their input. Use this sparingly — only when the ambiguity is blocking "
        "and no reasonable default exists. Do not ask for information you can infer."
    ),
    "input_schema": {
        "type": "object",
        "properties": {
            "question": {
                "type": "string",
                "description": "The single, specific question to ask.",
            },
            "options": {
                "type": "array",
                "items": {"type": "string"},
                "description": "Optional list of valid choices. Omit for free-form answers.",
            },
            "default": {
                "type": "string",
                "description": "The value to use if the human does not respond within the timeout.",
            },
        },
        "required": ["question"],
    },
}

async def handle_ask_human(params: dict, timeout: float = 300.0) -> str:
    q = PendingQuestion(
        question=params["question"],
        options=params.get("options"),
        default=params.get("default"),
    )
    _questions[q.id] = q

    try:
        await asyncio.wait_for(q.answer_event.wait(), timeout=timeout)
        return q.answer or q.default or "No answer provided"
    except asyncio.TimeoutError:
        del _questions[q.id]
        if q.default:
            return f"[TIMEOUT] No response received. Using default: {q.default}"
        return "[TIMEOUT] No response received and no default set."
    finally:
        _questions.pop(q.id, None)

import anthropic

client = anthropic.Anthropic()

async def run_agent_with_clarification(
    system: str,
    messages: list[dict],
    tools: list[dict],
    max_iters: int = 30,
) -> str:
    # Prepend the ask_human tool
    all_tools = [ASK_HUMAN_TOOL] + tools

    for _ in range(max_iters):
        resp = client.messages.create(
            model="claude-opus-4-8",
            max_tokens=4096,
            system=system,
            messages=messages,
            tools=all_tools,
        )
        if resp.stop_reason == "end_turn":
            return " ".join(b.text for b in resp.content if hasattr(b, "text"))

        tool_results = []
        for block in resp.content:
            if block.type != "tool_use":
                continue
            if block.name == "ask_human":
                answer = await handle_ask_human(block.input)
                tool_results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": answer,
                })
            else:
                result = await _execute_tool(block.name, block.input)
                tool_results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": result,
                })

        messages = messages + [
            {"role": "assistant", "content": resp.content},
            {"role": "user", "content": tool_results},
        ]

    return "max_iterations reached"

from fastapi import FastAPI, HTTPException
from pydantic import BaseModel

app = FastAPI()

class AnswerBody(BaseModel):
    answer: str

@app.get("/questions")
def list_questions():
    return [
        {
            "id": q.id,
            "question": q.question,
            "options": q.options,
            "default": q.default,
        }
        for q in _questions.values()
    ]

@app.post("/questions/{question_id}/answer")
def answer_question(question_id: str, body: AnswerBody):
    q = _questions.get(question_id)
    if not q:
        raise HTTPException(404, "Question not found or already answered")
    if q.options and body.answer not in q.options:
        raise HTTPException(
            400,
            f"Invalid answer. Valid options: {q.options}",
        )
    q.answer = body.answer
    q.answer_event.set()
    return {"status": "answered", "question_id": question_id}

