from collections import deque
from datetime import datetime, UTC, timedelta

class QuestionBudget:
    def __init__(self, max_per_hour: int = 10):
        self._max = max_per_hour
        self._timestamps: deque = deque()

    def can_ask(self) -> bool:
        now = datetime.now(UTC)
        cutoff = now - timedelta(hours=1)
        # Drop timestamps older than 1 hour
        while self._timestamps and self._timestamps[0] < cutoff:
            self._timestamps.popleft()
        return len(self._timestamps) < self._max

    def record_question(self):
        self._timestamps.append(datetime.now(UTC))

    @property
    def remaining(self) -> int:
        return max(0, self._max - len(self._timestamps))

budget = QuestionBudget(max_per_hour=5)

async def handle_ask_human_budgeted(params: dict, timeout: float = 300.0) -> str:
    if not budget.can_ask():
        # Fall back to default if budget exceeded
        default = params.get("default")
        if default:
            return f"[BUDGET EXCEEDED] Using default: {default}"
        return "[BUDGET EXCEEDED] Too many questions this session. Proceeding with best-guess interpretation."
    budget.record_question()
    return await handle_ask_human(params, timeout)

from enum import StrEnum

class AmbiguityType(StrEnum):
    SCOPE       = "scope"        # which records/items to affect
    FORMAT      = "format"       # output format or structure
    ENVIRONMENT = "environment"  # which deployment target
    TIMERANGE   = "timerange"    # which date/time window
    IDENTITY    = "identity"     # which user/entity to operate on

AMBIGUITY_TEMPLATES: dict[AmbiguityType, dict] = {
    AmbiguityType.SCOPE: {
        "question": "Which records should I {verb}?",
        "options": ["All matching records", "Only records modified today", "Let me specify a filter"],
        "default": "Only records modified today",
    },
    AmbiguityType.ENVIRONMENT: {
        "question": "Which environment should I target?",
        "options": ["staging", "production"],
        "default": "staging",
    },
    AmbiguityType.TIMERANGE: {
        "question": "What time range should I use for {context}?",
        "options": ["Last 7 days", "Last 30 days", "Last 90 days"],
        "default": "Last 30 days",
    },
}

def build_question(ambiguity_type: AmbiguityType, **kwargs) -> dict:
    template = AMBIGUITY_TEMPLATES.get(ambiguity_type, {})
    question = template.get("question", "Please clarify: {context}").format(**kwargs)
    return {
        "question": question,
        "options": template.get("options"),
        "default": template.get("default"),
    }
